 32 |         ViewMode::Bus if app.state.bus_log.filter_input_mode => handle_enter_bus_filter(app),
 33 |         ViewMode::Bus => app.state.bus_log.enter_detail(),
 34 |         ViewMode::Chat => {
 35 |             handle_enter_chat(
 36 |                 app,
 37 |                 cwd,
 38 |                 session,
 39 |                 registry,
 40 |                 worker_bridge,
 41 |                 event_tx,
 42 |                 result_tx,
 43 |             )
 44 |             .await
 45 |         }
 46 |         ViewMode::Model => crate::tui::app::model_picker::apply_selected_model(app, session),
 47 |         ViewMode::Settings | ViewMode::Lsp | ViewMode::Rlm => {}
 48 |     }
 49 | }
