 51 | pub async fn handle_backspace(app: &mut App) {
 52 |     if symbol_search_active(app) {
 53 |         app.state.symbol_search.handle_backspace();
 54 |         refresh_symbol_search(app).await;
 55 |     } else if app.state.view_mode == ViewMode::Bus && app.state.bus_log.filter_input_mode {
 56 |         app.state.bus_log.pop_filter_char();
 57 |         app.state.status = if app.state.bus_log.filter.is_empty() {
 58 |             "Protocol filter cleared".to_string()
 59 |         } else {
 60 |             format!("Protocol filter: {}", app.state.bus_log.filter)
 61 |         };
 62 |     } else if app.state.view_mode == ViewMode::Model {
 63 |         app.state.model_filter_backspace();
 64 |     } else if app.state.view_mode == ViewMode::Chat && !app.state.processing {
 65 |         app.state.delete_backspace();
 66 |         if app.state.input.is_empty() {
 67 |             app.state.input_mode = InputMode::Normal;
 68 |         } else if app.state.input.starts_with('/') {
 69 |             app.state.input_mode = InputMode::Command;
 70 |         }
 71 |     }
 72 | }
