100 |         && !modifiers.contains(KeyModifiers::ALT)
101 |         && symbol_search_active(app)
102 |     {
103 |         app.state.symbol_search.handle_char(c);
104 |         refresh_symbol_search(app).await;
105 |     } else if app.state.view_mode == ViewMode::Bus
106 |         && app.state.bus_log.filter_input_mode
107 |         && !modifiers.contains(KeyModifiers::CONTROL)
108 |         && !modifiers.contains(KeyModifiers::ALT)
109 |     {
110 |         app.state.bus_log.push_filter_char(c);
111 |         app.state.status = format!("Protocol filter: {}", app.state.bus_log.filter);
112 |     } else if app.state.view_mode == ViewMode::Model
113 |         && !modifiers.contains(KeyModifiers::CONTROL)
114 |         && !modifiers.contains(KeyModifiers::ALT)
115 |     {
116 |         app.state.model_filter_push(c);
117 |     } else if app.state.view_mode == ViewMode::Chat
118 |         && !modifiers.contains(KeyModifiers::CONTROL)
119 |         && !modifiers.contains(KeyModifiers::ALT)
120 |         && !app.state.processing
121 |     {
122 |         app.state.input_mode = if app.state.input.is_empty() && c == '/' {
123 |             InputMode::Command
124 |         } else if app.state.input.starts_with('/') || c == '/' {
125 |             InputMode::Command
126 |         } else {
127 |             InputMode::Editing
128 |         };
129 |         app.state.insert_char(c);
130 |     }
131 | }
