133 | async fn handle_enter_sessions(app: &mut App, cwd: &Path, session: &mut Session) {
134 |     let session_id = app
135 |         .state
136 |         .filtered_sessions()
137 |         .get(app.state.selected_session)
138 |         .map(|(orig_idx, _)| app.state.sessions[*orig_idx].id.clone());
139 |     if let Some(session_id) = session_id {
140 |         match Session::load(&session_id).await {
141 |             Ok(loaded) => {
142 |                 *session = loaded;
143 |                 app.state.session_id = Some(session.id.clone());
144 |                 sync_messages_from_session(app, session);
145 |                 refresh_sessions(app, cwd).await;
146 |                 app.state.clear_session_filter();
147 |                 return_to_chat(app);
148 |                 app.state.status = format!(
149 |                     "Loaded session {}",
150 |                     session.title.clone().unwrap_or_else(|| session.id.clone())
151 |                 );
152 |             }
153 |             Err(err) => {
154 |                 app.state.status = format!("Failed to load session: {err}");
155 |             }
156 |         }
157 |     }
158 | }
