169 | async fn handle_enter_chat(
170 |     app: &mut App,
171 |     cwd: &Path,
172 |     session: &mut Session,
173 |     registry: &Option<Arc<ProviderRegistry>>,
174 |     worker_bridge: &Option<TuiWorkerBridge>,
175 |     event_tx: &mpsc::Sender<SessionEvent>,
176 |     result_tx: &mpsc::Sender<anyhow::Result<Session>>,
177 | ) {
178 |     if app.state.processing {
179 |         app.state.status = "Still processing previous request…".to_string();
180 |         return;
181 |     }
182 | 
183 |     let prompt = app.state.input.trim().to_string();
184 |     if !prompt.is_empty() {
185 |         app.state.push_history(prompt.clone());
186 |     }
187 | 
188 |     if prompt.starts_with('/') {
189 |         handle_slash_command(app, cwd, session, registry.as_ref(), &prompt).await;
190 |         app.state.clear_input();
191 |         return;
192 |     }
193 | 
194 |     if prompt.is_empty() {
195 |         return;
196 |     }
197 | 
198 |     app.state
199 |         .messages
200 |         .push(ChatMessage::new(MessageType::User, prompt.clone()));
201 |     app.state.clear_input();
202 |     handle_processing_started(app, worker_bridge).await;
203 |     app.state.status = "Submitting prompt…".to_string();
204 |     app.state.scroll_to_bottom();
205 | 
206 |     if let Some(registry) = registry {
207 |         let mut session_for_task = session.clone();
208 |         let event_tx = event_tx.clone();
209 |         let result_tx = result_tx.clone();
210 |         let registry = Arc::clone(registry);
211 |         tokio::spawn(async move {
212 |             let result = session_for_task
213 |                 .prompt_with_events(&prompt, event_tx, registry)
214 |                 .await
215 |                 .map(|_| session_for_task);
216 |             let _ = result_tx.send(result).await;
217 |         });
218 |     } else {
219 |         handle_processing_stopped(app, worker_bridge).await;
220 |         app.state.messages.push(ChatMessage::new(
221 |             MessageType::Error,
222 |             "No providers available. Configure credentials first (for example: `codetether auth codex` or `codetether auth copilot`).",
223 |         ));
224 |         app.state.status = "No providers configured".to_string();
225 |         app.state.scroll_to_bottom();
226 |     }
227 | }

