  9 | pub fn handle_escape(app: &mut App) {
 10 |     if symbol_search_active(app) {
 11 |         app.state.symbol_search.close();
 12 |         app.state.status = "Closed symbol search".to_string();
 13 |     } else if app.state.show_help {
 14 |         app.state.show_help = false;
 15 |         app.state.status = "Closed help".to_string();
 16 |     } else if app.state.model_picker_active {
 17 |         close_model_picker(app);
 18 |         app.state.status = "Closed model picker".to_string();
 19 |     } else {
 20 |         match app.state.view_mode {
 21 |             ViewMode::Sessions => {
 22 |                 app.state.clear_session_filter();
 23 |                 return_to_chat(app);
 24 |             }
 25 |             ViewMode::Swarm if app.state.swarm.detail_mode => app.state.swarm.exit_detail(),
 26 |             ViewMode::Ralph if app.state.ralph.detail_mode => app.state.ralph.exit_detail(),
 27 |             ViewMode::Bus if app.state.bus_log.filter_input_mode => {
 28 |                 app.state.bus_log.exit_filter_mode();
 29 |                 app.state.status = "Protocol filter closed".to_string();
 30 |             }
 31 |             ViewMode::Bus if app.state.bus_log.detail_mode => app.state.bus_log.exit_detail(),
 32 |             ViewMode::Chat => app.state.input_mode = InputMode::Normal,
 33 |             _ => return_to_chat(app),
 34 |         }
 35 |     }
 36 | }
